import hmac
import hashlib
import base64
import struct
import time
import qrcode
import io
import secrets
from typing import Optional, Tuple


class TOTPAuthenticator:
    def __init__(self, issuer: str = "MyApp", digits: int = 6, period: int = 30, algorithm: str = 'sha1'):
        self.issuer = issuer
        self.digits = digits
        self.period = period
        self.algorithm = algorithm.lower()
        
        self.hash_algorithms = {
            'sha1': hashlib.sha1,
            'sha256': hashlib.sha256,
            'sha512': hashlib.sha512
        }
    
    def generate_secret(self, length: int = 32) -> str:
        random_bytes = secrets.token_bytes(length)
        secret = base64.b32encode(random_bytes).decode('utf-8')
        return secret.rstrip('=')
    
    def get_hotp(self, secret: str, counter: int) -> str:
        secret_bytes = self._decode_secret(secret)
        counter_bytes = struct.pack('>Q', counter)
        
        hash_func = self.hash_algorithms.get(self.algorithm, hashlib.sha1)
        hmac_hash = hmac.new(secret_bytes, counter_bytes, hash_func).digest()
        
        offset = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
        
        hotp = truncated % (10 ** self.digits)
        return str(hotp).zfill(self.digits)
    
    def get_totp(self, secret: str, timestamp: Optional[int] = None) -> str:
        if timestamp is None:
            timestamp = int(time.time())
        
        counter = timestamp // self.period
        return self.get_hotp(secret, counter)
    
    def verify_totp(self, secret: str, token: str, timestamp: Optional[int] = None, window: int = 1) -> bool:
        if timestamp is None:
            timestamp = int(time.time())
        
        if len(token) != self.digits:
            return False
        
        current_counter = timestamp // self.period
        
        for i in range(-window, window + 1):
            counter = current_counter + i
            expected_token = self.get_hotp(secret, counter)
            if self._constant_time_compare(token, expected_token):
                return True
        
        return False
    
    def get_provisioning_uri(self, secret: str, account_name: str) -> str:
        params = {
            'secret': secret,
            'issuer': self.issuer,
            'algorithm': self.algorithm.upper(),
            'digits': self.digits,
            'period': self.period
        }
        
        param_str = '&'.join([f'{k}={v}' for k, v in params.items()])
        uri = f'otpauth://totp/{self.issuer}:{account_name}?{param_str}'
        return uri
    
    def generate_qr_code(self, secret: str, account_name: str) -> bytes:
        uri = self.get_provisioning_uri(secret, account_name)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        img_bytes = io.BytesIO()
        img.save(img_bytes, format='PNG')
        img_bytes.seek(0)
        
        return img_bytes.getvalue()
    
    def save_qr_code(self, secret: str, account_name: str, filename: str) -> None:
        qr_data = self.generate_qr_code(secret, account_name)
        with open(filename, 'wb') as f:
            f.write(qr_data)
    
    def _decode_secret(self, secret: str) -> bytes:
        padding = '=' * ((8 - len(secret) % 8) % 8)
        secret_padded = secret + padding
        return base64.b32decode(secret_padded, casefold=True)
    
    def _constant_time_compare(self, a: str, b: str) -> bool:
        if len(a) != len(b):
            return False
        
        result = 0
        for x, y in zip(a, b):
            result |= ord(x) ^ ord(y)
        
        return result == 0


class UserTOTPManager:
    def __init__(self, issuer: str = "MyApp"):
        self.authenticator = TOTPAuthenticator(issuer=issuer)
        self.users = {}
    
    def register_user(self, username: str) -> Tuple[str, str]:
        secret = self.authenticator.generate_secret()
        self.users[username] = {
            'secret': secret,
            'verified': False
        }
        
        uri = self.authenticator.get_provisioning_uri(secret, username)
        return secret, uri
    
    def get_qr_code(self, username: str) -> Optional[bytes]:
        if username not in self.users:
            return None
        
        secret = self.users[username]['secret']
        return self.authenticator.generate_qr_code(secret, username)
    
    def verify_and_enable(self, username: str, token: str) -> bool:
        if username not in self.users:
            return False
        
        secret = self.users[username]['secret']
        is_valid = self.authenticator.verify_totp(secret, token)
        
        if is_valid:
            self.users[username]['verified'] = True
        
        return is_valid
    
    def authenticate(self, username: str, token: str) -> bool:
        if username not in self.users:
            return False
        
        if not self.users[username]['verified']:
            return False
        
        secret = self.users[username]['secret']
        return self.authenticator.verify_totp(secret, token)
    
    def get_user_secret(self, username: str) -> Optional[str]:
        if username not in self.users:
            return None
        return self.users[username]['secret']
    
    def is_user_verified(self, username: str) -> bool:
        if username not in self.users:
            return False
        return self.users[username]['verified']
    
    def remove_user(self, username: str) -> bool:
        if username in self.users:
            del self.users[username]
            return True
        return False


